func MultipleErrorChecks(a, b int) (int, error) {
	if a < 0 {
		return 0, errors.New("first parameter cannot be negative")
	}
	if b == 0 {
		return 0, errors.New("second parameter cannot be zero")
	}
	if a > 1000 {
		return 0, errors.New("first parameter too large")
	}
	return a / b, nil
}

